export async function GET(req: NextRequest) {
  if (req.nextUrl.searchParams.get('secret') !== SEED_SECRET) {
    return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  }
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const key = process.env.SUPABASE_SERVICE_ROLE_KEY
  if (!url || !key) return NextResponse.json({ error: 'env missing' }, { status: 500 })
  const supabase = createClient(url, key)

  // upload cover
  await supabase.storage.createBucket('blog', { public: true }).catch(() => {})
  const buffer = Buffer.from(COVER_B64, 'base64')
  const path = `covers/copa-do-mundo-${Date.now()}.png`
  const up = await supabase.storage.from('blog').upload(path, buffer, { contentType: 'image/png', upsert: true })
  let coverUrl: string | null = null
  if (!up.error) coverUrl = supabase.storage.from('blog').getPublicUrl(path).data.publicUrl

  await supabase.from('blog_posts').delete().eq('slug', post.slug)
  const { error } = await supabase.from('blog_posts').insert({ ...post, cover_image: coverUrl })
  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json({ ok: true, cover: coverUrl })
}
